sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading || !newValue)
        return;

    // Convert selected purchase date
    var purchaseDate = new Date(newValue);

    // Add 6 months
    purchaseDate.setMonth(
        purchaseDate.getMonth() + 6
    );

    // Format date as YYYY-MM-DD
    var year = purchaseDate.getFullYear();
    var month = ('0' + (purchaseDate.getMonth() + 1)).slice(-2);
    var day = ('0' + purchaseDate.getDate()).slice(-2);

    var nextMaintenanceDate =
        year + '-' + month + '-' + day;

    // Set Next Maintenance Date
    g_form.setValue(
        'next_maintenance_date',
        nextMaintenanceDate
    );
}
